class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int s1Len = s1.size(), s2Len = s2.size();
        if (s1Len * n1 < s2Len * n2) return 0;

        vector<int> s2Count(s2Len, 0);
        for (int i = 0; i < s2Len; ++i) {
            for (int j = 0; j < s1Len; ++j) {
                if (s1[j] == s2[i]) {
                    s2Count[i] = j + 1;
                    break;
                }
            }
        }

        int res = 0, cur = 0;
        for (int i = 0; i < s2Len; ++i) {
            if (s2Count[i] == 0) continue;
            cur += s2Count[i];
            if (cur > s1Len * n1) break;
            ++res;
        }
        return res / s2Len * n1;
    }
};
```
